import{_ as a,o as t,c as i,a3 as s}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Utils","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/utils.md","filePath":"cosmos/framework/packages/utils.md","lastUpdated":1783216089000}'),o={name:"cosmos/framework/packages/utils.md"};function r(l,e,n,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="xihan-framework-utils" tabindex="-1">XiHan.Framework.Utils <a class="header-anchor" href="#xihan-framework-utils" aria-label="Permalink to &quot;XiHan.Framework.Utils&quot;">​</a></h1><blockquote><p>零依赖通用工具库：字符串处理、加密算法、异步编程、序列化、集合操作、反射、网络通信、文件 IO、数学计算、时间处理等。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Utils</code></li><li><strong>模块类</strong>：—（无模块类，直接引用）</li><li><strong>所在层</strong>：公共层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Utils 是框架最底层的通用工具库，把日常开发中反复要写的杂活（加密、序列化、反射、集合处理、文件读写、时间换算等）封装成一组静态 Helper 与扩展方法。它几乎不依赖其它框架模块，几乎所有上层包都会间接用到它。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要现成的加密/哈希、JSON/XML/YAML 序列化、压缩、掩码脱敏等基础能力。</li><li>想用扩展方法简化字符串、集合、枚举、日期时间、类型反射的常见操作。</li><li>处理文件、目录、路径、流，或做 DNS/Ping/WebSocket/SSE 等网络辅助。</li><li>作为自己业务工具类的底座，避免重复造轮子。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Utils</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><p>纯工具库，直接引用即可，无需 <code>[DependsOn]</code>。调用其中的静态 Helper 或扩展方法即可使用。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>安全与加密</strong>（<code>Security</code>）：AES/DES/RSA/ECDSA/DSA/ECIES 加解密、Hash/HMAC、GUID、OTP、掩码脱敏、密码强度、随机编码。</li><li><strong>序列化</strong>（<code>Serialization</code>）：JSON、XML、YAML 的序列化与反序列化封装。</li><li><strong>集合与 LINQ</strong>（<code>Collections</code> / <code>Linq</code>）：List、Dictionary、Enumerable、Queue、Stack、Tree 等扩展。</li><li><strong>反射</strong>（<code>Reflections</code>）：类型、成员、方法、属性、字段的反射辅助。</li><li><strong>文件与 IO</strong>（<code>IO</code>）：文件、目录、路径、流、压缩处理。</li><li><strong>网络</strong>（<code>Net</code>）：DNS、Ping、IP 格式化，以及 Http / WebSocket / SSE 辅助。</li><li><strong>时间与数学</strong>（<code>Timing</code> / <code>Maths</code>）：日期时间区间、农历、计时，数字与金额格式化。</li><li><strong>扩展方法</strong>（<code>Extensions</code>）：字符串、日期时间、枚举、类型、编码、流等常用扩展。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>ReflectionHelper</code></td><td>反射辅助，如读取入口程序集版本</td></tr><tr><td><code>HashHelper</code> / <code>AesHelper</code> / <code>RsaHelper</code></td><td>常用哈希与对称/非对称加解密</td></tr><tr><td><code>JsonHelper</code></td><td>JSON 序列化/反序列化封装</td></tr><tr><td><code>FileHelper</code> / <code>DirectoryHelper</code> / <code>PathHelper</code></td><td>文件、目录、路径操作</td></tr><tr><td><code>MaskHelper</code></td><td>敏感信息掩码脱敏</td></tr><tr><td><code>StringExtensions</code> / <code>EnumExtensions</code> / <code>TypeExtensions</code></td><td>常用扩展方法集</td></tr></tbody></table><h2 id="快速示例" tabindex="-1">快速示例 <a class="header-anchor" href="#快速示例" aria-label="Permalink to &quot;快速示例&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 读取入口程序集版本</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> version</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ReflectionHelper.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetEntryAssemblyVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><p>无框架内部业务依赖，仅在编译期引用 <a href="./analyzers">XiHan.Framework.Analyzers</a> 做文件头规范检查，运行时等价于零依赖，直接构建在 BCL 之上。</p><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./core">XiHan.Framework.Core</a> — 核心库，构建在 Utils 之上。</li><li><a href="./metadata">XiHan.Framework.Metadata</a> — 框架元数据，同为公共/元数据层基础包。</li></ul>`,21)])])}const u=a(o,[["render",r]]);export{k as __pageData,u as default};
